/**
 * VALIDATION RULES:
 * Temperature: 10–40°C (reasonable farm range)
 * Humidity: 0–100%
 * Soil: 0–100%
 * All required fields must be present
 */
const d = msg.payload;
const errors = [];

if (!d.node_id)               errors.push('missing node_id');
if (!d.temperature && d.temperature !== 0) errors.push('missing temperature');
if (!d.humidity && d.humidity !== 0)       errors.push('missing humidity');
if (!d.soil_pct && d.soil_pct !== 0)       errors.push('missing soil_pct');
if (d.temperature < 10 || d.temperature > 40) errors.push('temperature out of range');
if (d.humidity < 0 || d.humidity > 100)       errors.push('humidity out of range');
if (d.soil_pct < 0 || d.soil_pct > 100)       errors.push('soil_pct out of range');

if (errors.length > 0) {
  node.warn('Validation failed for ' + d.node_id + ': ' + errors.join(', '));
  return null; // Drop invalid reading
}

// Add server-side timestamp
msg.payload.server_ts = new Date().toISOString();
msg.payload.valid = true;

return msg;

/**
 * CLR THRESHOLD RULES (from literature):
 * HIGH RISK:   humidity >= 80% AND temperature 21–25°C
 * MODERATE:    humidity 70–79% AND temperature 20–26°C
 * LOW:         everything else
 *
 * If HIGH or MODERATE → trigger ML model + Gemini
 */
const d = msg.payload;
let risk = 'LOW';

if (d.humidity >= 80 && d.temperature >= 21 && d.temperature <= 25) {
  risk = 'HIGH';
} else if (d.humidity >= 70 && d.temperature >= 20 && d.temperature <= 26) {
  risk = 'MODERATE';
}

msg.payload.clr_risk_preliminary = risk;

if (risk === 'HIGH' || risk === 'MODERATE') {
  return [msg, null]; // Send to ML model
} else {
  return [null, msg]; // Skip ML, store only
}

// Prepare MySQL insert payload
// This connects to your mysql2 node or custom HTTP endpoint
msg.payload = {
  query: 'INSERT INTO sensor_readings (node_id, position, temperature, humidity, soil_pct, clr_risk, recommendation, recorded_at) VALUES (?, ?, ?, ?, ?, ?, ?, NOW())',
  params: [
    msg.payload.node_id,
    msg.payload.position,
    msg.payload.temperature,
    msg.payload.humidity,
    msg.payload.soil_pct,
    msg.payload.clr_risk_preliminary || 'LOW',
    msg.payload.recommendation || null
  ]
};
return msg;
